mapper.insert:
INSERT INTO TMB_PUSHMSG_CAMP (
       MSG_SEQ
     , CAMP_SEQ
     , PUSH_TYPE
     , PUSH_TOKEN
     , MSG_TYPE
     , APP_NO
     , RECV_YN
     , RESV_DT
     , RETRY_CNT
     , TEST_YN
     , STS_CD
     , REG_ID
     , REG_DT
     , KIND
     , SVR_ID
     , SEND_DEPARTMENT
     , BNKING_ID
     , BAND_SEQNO
) VALUES (
       TMB_PUSHMSG_CAMP_SEQ.NEXTVAL
     , #{ campSeq }
     ,(SELECT (CASE WHEN OPERTYPE = '1' THEN 'A' ELSE  'G' END) AS PUSH_TYPE FROM TMB_OBJ_USR_MGT WHERE BNKING_ID = #{bnkingId})
    , (SELECT CNFRM_NO FROM TMB_OBJ_USR_MGT WHERE BNKING_ID = #{bnkingId})
     , #{ msgType }
     , '3'
     , #{ recvYN }
     , TO_DATE(#{ resvDt }, 'YYYYMMDDhh24miss')
     , #{ retryCnt }
     , #{ testYN }
     , #{ stsCd }
     , #{ regId }
     , CURRENT_DATE
     , #{ kind }
     , (SELECT SVR_ID FROM TMB_SVR)
     , #{ sendDepartment }
     , #{ bnkingId }
     , #{ bandSeqNo }
)
